I apologize for any confusion in my previous responses. You can rewrite your problem using auxiliary variables to avoid needing to register any functions or use the `@NL*` macros. Here's an example of how you can do this:

```julia
function opt_portfolio_both(rates_of_return, r_min, var_max)
    portfolio = Model(Ipopt.Optimizer)
    set_silent(portfolio)
    r_mean = mean(rates_of_return, dims=1)
    covar = cov(rates_of_return)
    @variable(portfolio, x[1:size(rates_of_return)[2]] >= 0)
    # Define auxiliary variables for mean and variance of the portfolio
    @variable(portfolio, mu)
    @variable(portfolio, sigma_sq)

    @constraint(portfolio, sum(x) == 1)
    @constraint(portfolio, mu == sum(x[i] * r_mean'[i] for i in 1:length(x)))
    @constraint(portfolio, sigma_sq == sum(x[i] * covar[i, j] * x[j] for i in 1:length(x), j in 1:length(x))) 
    @constraint(portfolio, mu >= r_min)
    @constraint(portfolio, sigma_sq <= var_max)

    # Maximize mu subject to sum of (x1^2, x2^2, x3^2, ...) <=> Minimize -mu
    @objective(portfolio, Min, -mu)
    optimize!(portfolio)
    weights_opt = value.(x)
    mean_opt = value(mu)
    sdev_opt = sqrt(value(sigma_sq))
    return weights_opt, mean_opt, sdev_opt
end
```

In this example, we are defining auxiliary variables `mu` and `sigma_sq` that represent the mean and variance of the portfolio, respectively, instead of directly using your previously defined functions. Linear constraints are used to relate these auxiliary variables to the decision variables `x`, instead of computing the portfolio mean and variance directly in the objective function.

